import { useState, useEffect } from 'react';
import axiosInstance from '../axiosConfig';
import TourForm from '../components/TourForm'; // 注意：我們稍後要改組件名稱
import TourList from '../components/TourList'; // 注意：我們稍後要改組件名稱
import { useAuth } from '../context/AuthContext';

const Tours = () => {
  const { user } = useAuth();
  const [tours, setTours] = useState([]);
  const [editingTour, setEditingTour] = useState(null);

  useEffect(() => {
    const fetchTours = async () => {
      try {
        // 對應你剛才成功的後端 API 路由
        const response = await axiosInstance.get('/api/tours', {
          headers: { Authorization: `Bearer ${user.token}` },
        });
        setTours(response.data);
      } catch (error) {
        console.error('抓取行程失敗:', error);
        // 如果還沒處理後端權限，這裡暫時拿掉 headers 測試也可以
      }
    };

    if (user) fetchTours();
  }, [user]);

  return (
    <div className="container mx-auto p-6">
      <h1 className="text-2xl font-bold mb-4">Tour Package Management (TPMS)</h1>

      {/* 這裡是新增與編輯旅遊產品的表單 */}
      <TourForm
        tours={tours}
        setTours={setTours}
        editingTour={editingTour}
        setEditingTour={setEditingTour}
      />

      {/* 這裡是旅遊產品列表 */}
      <TourList 
        tours={tours} 
        setTours={setTours} 
        setEditingTour={setEditingTour} 
      />
    </div>
  );
};

export default Tours;
